final:
module RefModule(
    input a,
    input b,
    input carry_in,
    output sum,
    output carry_out
);

assign sum = a ^ b ^ carry_in;
  wire temp1_(a & b) | (b & carry_in) = (a & b) | (b & carry_in);
  wire temp2_(a & carry_in) = (a & carry_in);
  assign carry_out = temp1_(a & b) | (b & carry_in) | temp2_(a & carry_in);

endmodule
